#!/usr/bin/env python3
"""
Home Automation Controller for Raspberry Pi
Handles sensors (PIR, LDR), actuators (relay), and cloud communication
"""
import json
import time
import threading
from datetime import datetime

# Import GPIO libraries (using mock for demonstration)
try:
 import RPi.GPIO as GPIO
 GPIO_AVAILABLE = True
except ImportError:
 GPIO_AVAILABLE = False
 print("Running in simulation mode")

# Configuration Constants
PIR_PIN = 17 # GPIO pin for PIR motion sensor
LDR_PIN = 4 # GPIO pin for LDR (analog via ADC)
RELAY_PIN = 27 # GPIO pin for relay control
LIGHT_THRESHOLD = 30 # Percentage
AUTO_OFF_DELAY = 60 # Seconds

class HomeAutomationController:
 def __init__(self):
 self.light_status = False
 self.motion_detected = False
 self.light_intensity = 100
 self.auto_off_timer = None
 self.system_active = True
 self.cloud_connected = False

 if GPIO_AVAILABLE:
 self.setup_gpio()

 def setup_gpio(self):
 """Initialize GPIO pins for sensors and actuators"""
 GPIO.setmode(GPIO.BCM)
 GPIO.setup(PIR_PIN, GPIO.IN) # Motion sensor input
 GPIO.setup(RELAY_PIN, GPIO.OUT) # Relay output
 GPIO.output(RELAY_PIN, GPIO.LOW) # Start with relay off
 print("[GPIO] Initialized successfully")

 def read_motion_sensor(self):
 """Read PIR motion sensor"""
 if GPIO_AVAILABLE:
 return GPIO.input(PIR_PIN) == 1
 else:
 # Simulation mode - return random for demo
 return False

 def read_light_sensor(self):
 """Read LDR light intensity sensor (0-100%)"""
 if GPIO_AVAILABLE:
 # Would use ADC to read analog value
 # Convert to percentage
 pass
 else:
 # Simulation: return varying light levels
 return self.light_intensity

 def control_relay(self, state):
 """Control the relay to switch light on/off"""
 if GPIO_AVAILABLE:
 GPIO.output(RELAY_PIN, GPIO.HIGH if state else GPIO.LOW)
 self.light_status = state
 print(f"[RELAY] Light {'ON' if state else 'OFF'}")

 def start_auto_off_timer(self):
 """Start timer to auto-turn-off light after delay"""
 if self.auto_off_timer:
 self.auto_off_timer.cancel()

 self.auto_off_timer = threading.Timer(AUTO_OFF_DELAY, self.auto_turn_off)
 self.auto_off_timer.start()

 def auto_turn_off(self):
 """Callback to turn off light after no motion"""
 if not self.motion_detected:
 self.control_relay(False)
 self.publish_telemetry()
 print("[AUTO-OFF] Light turned off - no motion detected")

 def publish_telemetry(self):
 """Send sensor data to cloud platform"""
 telemetry = {
 "device_id": "home-automation-001",
 "timestamp": datetime.now().isoformat(),
 "sensors": {
 "motion_detected": self.motion_detected,
 "light_intensity": self.light_intensity
 },
 "actuators": {
 "light_status": "ON" if self.light_status else "OFF"
 }
 }

 # In production, this would publish to AWS IoT, Azure IoT Hub, etc.
 print(f"[CLOUD] Published: {json.dumps(telemetry, indent=2)}")
 return telemetry

 def automation_logic(self):
 """Main automation logic - the brain of the system"""
 self.motion_detected = self.read_motion_sensor()
 self.light_intensity = self.read_light_sensor()

 # Rule: Turn ON if motion detected AND room is dark
 if self.motion_detected and self.light_intensity < LIGHT_THRESHOLD:
 if not self.light_status:
 self.control_relay(True)
 self.start_auto_off_timer()
 print("[AUTOMATION] Light turned ON - Motion in low light")

 # Rule: Keep OFF if enough ambient light
 elif self.light_intensity >= LIGHT_THRESHOLD:
 if self.light_status:
 self.control_relay(False)
 print("[AUTOMATION] Light OFF - Sufficient ambient light")

 # Publish telemetry to cloud
 self.publish_telemetry()

 def run(self):
 """Main control loop"""
 print("[SYSTEM] Home Automation Controller Started")

 try:
 while self.system_active:
 self.automation_logic()
 time.sleep(0.5) # 500ms polling interval
 except KeyboardInterrupt:
 print("\n[SYSTEM] Shutting down...")
 self.control_relay(False)
 if GPIO_AVAILABLE:
 GPIO.cleanup()

# Run the controller
if __name__ == "__main__":
 controller = HomeAutomationController()
 controller.run()

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include "freertos/FreeRTOS.h"
#include "freertos/task.h"
#include "driver/gpio.h"
#include "esp_system.h"
#include "esp_wifi.h"
#include "esp_mqtt.h"
#include "esp_log.h"

// Configuration
#define PIR_SENSOR_PIN GPIO_NUM_4
#define LDR_SENSOR_PIN GPIO_NUM_34 // ADC pin
#define RELAY_PIN GPIO_NUM_18
#define LIGHT_THRESHOLD 30
#define AUTO_OFF_SECONDS 60

// MQTT Broker Configuration
#define MQTT_BROKER "mqtt://broker.hivemq.com"
#define MQTT_TOPIC "home/lighting/livingroom"

// Global state
static const char *TAG = "SmartLighting";
volatile int motion_detected = 0;
volatile int light_intensity = 100;
volatile int light_status = 0;
volatile int auto_off_ticks = 0;

// Function prototypes
void init_hardware(void);
void init_wifi(void);
void init_mqtt(void);
int read_pir_sensor(void);
int read_ldr_sensor(void);
void control_relay(int state);
void publish_status(void);
void automation_task(void *param);

/**
 * Initialize hardware peripherals
 */
void init_hardware(void) {
 // Configure PIR sensor pin as input
 gpio_config_t pir_conf = {
 .pin_bit_mask = (1ULL << PIR_SENSOR_PIN),
 .mode = GPIO_MODE_INPUT,
 .pull_up_en = GPIO_PULLUP_DISABLE,
 .pull_down_en = GPIO_PULLDOWN_DISABLE,
 .intr_type = GPIO_INTR_ANYEDGE
 };
 gpio_config(&pir_conf);

 // Configure relay pin as output
 gpio_config_t relay_conf = {
 .pin_bit_mask = (1ULL << RELAY_PIN),
 .mode = GPIO_MODE_OUTPUT,
 .pull_up_en = GPIO_PULLUP_DISABLE,
 .pull_down_en = GPIO_PULLDOWN_DISABLE,
 .intr_type = GPIO_INTR_DISABLE
 };
 gpio_config(&relay_conf);

 // Initialize ADC for LDR
 adc1_config_width(ADC_WIDTH_BIT_12);
 adc1_config_pin_atten(LDR_SENSOR_PIN, ADC_ATTEN_DB_11);

 ESP_LOGI(TAG, "Hardware initialized successfully");
}

/**
 * Read PIR motion sensor
 * Returns: 1 if motion detected, 0 otherwise
 */
int read_pir_sensor(void) {
 return gpio_get_level(PIR_SENSOR_PIN);
}

/**
 * Read LDR light sensor and convert to percentage
 * Returns: Light intensity 0-100%
 */
int read_ldr_sensor(void) {
 int adc_value = adc1_get_raw(LDR_SENSOR_PIN);
 // Convert ADC value (0-4095) to percentage
 // Lower ADC = higher light intensity for LDR connected to ground
 int percentage = 100 - ((adc_value * 100) / 4095);
 return percentage;
}

/**
 * Control relay to turn light on/off
 */
void control_relay(int state) {
 gpio_set_level(RELAY_PIN, state);
 light_status = state;

 if (state) {
 ESP_LOGI(TAG, "Light turned ON");
 auto_off_ticks = AUTO_OFF_SECONDS; // Reset auto-off timer
 } else {
 ESP_LOGI(TAG, "Light turned OFF");
 }
}

/**
 * Publish status to MQTT broker
 */
void publish_status(void) {
 char payload[256];
 snprintf(payload, sizeof(payload),
 "{\"device\":\"esp32-lighting\",\"motion\":%d,\"light_level\":%d,\"light_state\":%d,\"timestamp\":%lu}",
 motion_detected, light_intensity, light_status, (unsigned long)time(NULL));

 ESP_LOGI(TAG, "Publishing: %s", payload);
 // esp_mqtt_client_publish(client, MQTT_TOPIC, payload, 0, 0, 0);
}

/**
 * Main automation logic task
 * Runs continuously, implements the control algorithm
 */
void automation_task(void *param) {
 while (1) {
 // Read sensors
 motion_detected = read_pir_sensor();
 light_intensity = read_ldr_sensor();

 ESP_LOGD(TAG, "Motion: %d, Light: %d%%, Status: %d", 
 motion_detected, light_intensity, light_status);

 // Automation rules:
 // Rule 1: Turn ON if motion detected AND low light
 if (motion_detected && light_intensity < LIGHT_THRESHOLD) {
 if (!light_status) {
 control_relay(1);
 }
 auto_off_ticks = AUTO_OFF_SECONDS; // Reset timer on motion
 }
 // Rule 2: Turn OFF if sufficient ambient light
 else if (light_intensity >= LIGHT_THRESHOLD) {
 if (light_status) {
 control_relay(0);
 }
 }
 // Rule 3: Auto-off after timeout
 else if (light_status && !motion_detected) {
 auto_off_ticks--;
 if (auto_off_ticks <= 0) {
 control_relay(0);
 }
 }

 // Publish to cloud
 publish_status();

 // Delay 1 second
 vTaskDelay(pdMS_TO_TICKS(1000));
 }
}

/**
 * WiFi initialization
 */
void init_wifi(void) {
 wifi_config_t wifi_config = {
 .sta = {
 .ssid = "YourSSID",
 .password = "YourPassword",
 },
 };

 ESP_ERROR_CHECK(esp_wifi_init(&wifi_config));
 ESP_ERROR_CHECK(esp_wifi_set_mode(WIFI_MODE_STA));
 ESP_ERROR_CHECK(esp_wifi_set_config(ESP_IF_WIFI_STA, &wifi_config));
 ESP_ERROR_CHECK(esp_wifi_start());

 ESP_LOGI(TAG, "WiFi initialized");
}

/**
 * Application main entry point
 */
void app_main(void) {
 ESP_LOGI(TAG, "Smart Lighting Controller Starting...");

 // Initialize all subsystems
 init_hardware();
 init_wifi();
 // init_mqtt();

 // Create automation task
 xTaskCreate(automation_task, "automation_task", 4096, NULL, 5, NULL);

 ESP_LOGI(TAG, "System running");
}
